import math

def address_bits(num_words):
    return math.ceil(math.log2(num_words))

total_bits, word_bits = 1024, 8
num_words = total_bits // word_bits
n = address_bits(num_words)
print(f"{total_bits}비트 롬 = {word_bits}비트 워드 {num_words}개 -> 주소 입력선 {n}개, 출력선 {word_bits}개")
assert num_words == 128 and n == 7

class SimpleROM:
    def __init__(self, size):
        self.cells = [None] * size
    def write_once(self, addr, data):
        if self.cells[addr] is not None:
            raise PermissionError("이미 기록된 롬 셀은 다시 쓸 수 없습니다.")
        self.cells[addr] = data
    def read(self, addr):
        return self.cells[addr]

rom_ = SimpleROM(4)
rom_.write_once(0, 0b1010)
try:
    rom_.write_once(0, 0b0101)
    print("오류: 다시 쓰기가 허용되었음(잘못됨)")
except PermissionError:
    print("롬: 같은 주소에 두 번 쓰기 시도 -> 금지됨(비휘발성, 읽기 전용 특성)")

class SimpleRAM:
    def __init__(self, size):
        self.cells = [0] * size
    def write(self, addr, data):
        self.cells[addr] = data
    def read(self, addr):
        return self.cells[addr]
    def power_off(self):
        self.cells = [0] * len(self.cells)

ram = SimpleRAM(4)
ram.write(0, 0b1010)
ram.write(0, 0b0101)  # 자유롭게 덮어쓰기 가능
print("램: 같은 주소에 두 번 쓰기 ->", bin(ram.read(0)))
ram.power_off()
print("램: 전원 차단 후 ->", ram.read(0), "(휘발성: 데이터 소실)")
